import pytest


def max_subarray_sum(arr: list) -> int:
    if not arr:
        return 0
    max_sum = current = arr[0]
    for num in arr[1:]:
        current = max(num, current + num)
        max_sum = max(max_sum, current)
    return max_sum


class TestMaxSubarraySumHappyPath:
    """Tests for typical, expected inputs."""

    def test_classic_kadane_example(self):
        # Classic example: [-2, 1, -3, 4, -1, 2, 1, -5, 4] -> [4, -1, 2, 1] = 6
        assert max_subarray_sum([-2, 1, -3, 4, -1, 2, 1, -5, 4]) == 6

    def test_all_positive_numbers(self):
        # Entire array is the max subarray
        assert max_subarray_sum([1, 2, 3, 4, 5]) == 15

    def test_mixed_positive_and_negative(self):
        assert max_subarray_sum([3, -1, 4, -1, 5, -9, 2, 6]) == 10

    def test_max_at_beginning(self):
        assert max_subarray_sum([5, 4, -100, 1, 2]) == 9

    def test_max_at_end(self):
        assert max_subarray_sum([1, 2, -100, 4, 5]) == 9

    def test_max_in_middle(self):
        assert max_subarray_sum([-10, 1, 2, 3, -10]) == 6


class TestMaxSubarraySumEdgeCases:
    """Tests for edge cases."""

    def test_empty_list_returns_zero(self):
        assert max_subarray_sum([]) == 0

    def test_single_positive_element(self):
        assert max_subarray_sum([5]) == 5

    def test_single_negative_element(self):
        # When all elements are negative, return the largest (least negative)
        assert max_subarray_sum([-5]) == -5

    def test_single_zero_element(self):
        assert max_subarray_sum([0]) == 0

    def test_all_negative_numbers(self):
        # Should return the maximum (least negative) element
        assert max_subarray_sum([-3, -1, -4, -1, -5, -9, -2, -6]) == -1

    def test_all_zeros(self):
        assert max_subarray_sum([0, 0, 0, 0]) == 0

    def test_two_elements_positive(self):
        assert max_subarray_sum([1, 2]) == 3

    def test_two_elements_negative(self):
        assert max_subarray_sum([-1, -2]) == -1

    def test_two_elements_mixed(self):
        assert max_subarray_sum([-1, 2]) == 2
        assert max_subarray_sum([2, -1]) == 2

    def test_zeros_and_negatives(self):
        # Zero is greater than any negative number
        assert max_subarray_sum([-1, 0, -2, 0, -3]) == 0

    def test_large_array(self):
        # Array of 1000 ones should sum to 1000
        assert max_subarray_sum([1] * 1000) == 1000

    def test_alternating_signs(self):
        assert max_subarray_sum([1, -1, 1, -1, 1]) == 1

    def test_floats_work_too(self):
        # Function uses max() so it handles floats as well
        assert max_subarray_sum([1.5, -0.5, 2.0]) == 3.0

    def test_large_negative_followed_by_positives(self):
        assert max_subarray_sum([-1000, 1, 2, 3]) == 6

    def test_single_large_positive_among_negatives(self):
        assert max_subarray_sum([-5, -4, 100, -3, -2]) == 100


class TestMaxSubarraySumErrorCases:
    """Tests for invalid inputs that should raise errors."""

    def test_none_raises_type_error(self):
        with pytest.raises(TypeError):
            max_subarray_sum(None)

